package com.vidaysalud.veterinaria.notificacionservicio.controller;import com.vidaysalud.veterinaria.notificacionservicio.dto.*;import com.vidaysalud.veterinaria.notificacionservicio.service.NotificacionService;import jakarta.validation.Valid;import lombok.RequiredArgsConstructor;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;import java.time.LocalDateTime;import java.util.*;@RestController @RequestMapping("/api/v1/notificaciones") @RequiredArgsConstructor public class NotificacionController{private final NotificacionService s;@GetMapping public ResponseEntity<ApiResponse<List<NotificacionResponseDTO>>>l(){return ok("Notificaciones obtenidas",s.listar());}@GetMapping("/{id}")public ResponseEntity<ApiResponse<NotificacionResponseDTO>>b(@PathVariable Integer id){return ok("Notificación encontrada",s.buscar(id));}@GetMapping("/cliente/{id}")public ResponseEntity<ApiResponse<List<NotificacionResponseDTO>>>c(@PathVariable Integer id){return ok("Notificaciones del cliente",s.cliente(id));}@PostMapping public ResponseEntity<ApiResponse<NotificacionResponseDTO>>n(@Valid @RequestBody NotificacionRequestDTO d){return ResponseEntity.status(201).body(resp(HttpStatus.CREATED,"Notificación creada",s.crear(d)));}@PostMapping("/{id}/enviar")public ResponseEntity<ApiResponse<NotificacionResponseDTO>>e(@PathVariable Integer id){return ok("Notificación enviada",s.enviar(id));}@DeleteMapping("/{id}")public ResponseEntity<ApiResponse<Void>>d(@PathVariable Integer id){s.eliminar(id);return ok("Notificación eliminada",null);}private<T>ResponseEntity<ApiResponse<T>>ok(String m,T d){return ResponseEntity.ok(resp(HttpStatus.OK,m,d));}private<T>ApiResponse<T>resp(HttpStatus h,String m,T d){return ApiResponse.<T>builder().timestamp(LocalDateTime.now()).status(h.value()).mensaje(m).data(d).build();}}